button_animations.css:
{{BTN}}:hover { animation: {{ANIM}} 1.1s ease infinite; }
@keyframes {{ANIM}} {
  0%   { box-shadow: 0 0 0 0 rgba(0,0,0,.35); }
  70%  { box-shadow: 0 0 0 12px rgba(0,0,0,0); }
  100% { box-shadow: 0 0 0 0 rgba(0,0,0,0); }
}

{{BTN}}:hover { transform-origin: top center; animation: {{ANIM}} .7s ease; }
@keyframes {{ANIM}} {
  20%  { transform: rotate(8deg); }
  40%  { transform: rotate(-6deg); }
  60%  { transform: rotate(4deg); }
  80%  { transform: rotate(-2deg); }
  100% { transform: rotate(0); }
}

{{BTN}}:hover { animation: {{ANIM}} .8s ease; }
@keyframes {{ANIM}} {
  0%   { transform: scale(1, 1); }
  30%  { transform: scale(1.25, .75); }
  40%  { transform: scale(.75, 1.25); }
  55%  { transform: scale(1.15, .85); }
  70%  { transform: scale(.95, 1.05); }
  100% { transform: scale(1, 1); }
}

{{BTN}}:hover { animation: {{ANIM}} .45s ease; }
@keyframes {{ANIM}} {
  0%, 100% { transform: scale(1, 1); }
  50%      { transform: scale(1.1, .85); }
}
